import { useState } from 'react';
import './App.css';
import Layout from './components/Layout';

function App() {
  const [menuType, setMenuType] = useState('aboutme');

  const onClick = id => {
    console.log('onClick: '+id);
    debugger;
  };

  return (
    <div>
      <header>
        <ul>
          <li><p id="aboutme" onClick={onClick}>About Me</p></li>
          <li><p id="experience">Experience</p></li>
          <li><p id="projects">Projects</p></li>
          <li><p id="skills">Skills</p></li>
          <li><p id="photo">Photo</p></li>
        </ul>
      </header>

      <div className="wrapper">
        <div className="App-title">
          <div className="App-title-name">
            CHAERIN YU
          </div>
          <div className="App-title-name2">
            CHALLENGER
          </div>
        </div>
        <div className="App-contents">
          <Layout menuType={menuType} />
        </div>
        <div className="App-footer">
        Copyright 2021. Chaerin Yu. All rights reserved.
        </div>
      </div>

        {/* <div className="App-contents">
          <Layout />
        </div>
        <div className="App-footer"></div> */}
      </div>
  );
}

export default App;
